/* cloud+ :: content/domain2.js — lazy-loaded reading module for CV0-004 Domain 2 (Deployment, deep). */
window.CLOUDPLUS = window.CLOUDPLUS || {}; CLOUDPLUS.reading = CLOUDPLUS.reading || {};
